{
  "name": "Pathfinder: RIASEC Career Quest",
  "description": "A modern career interest test for high school students to discover their Holland Code and explore matching career pathways using the RIASEC model."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RIASECCategory {
  R = 'Realistic',
  I = 'Investigative',
  A = 'Artistic',
  S = 'Social',
  E = 'Enterprising',
  C = 'Conventional'
}

export type CategoryKey = 'R' | 'I' | 'A' | 'S' | 'E' | 'C';

export interface Question {
  id: number;
  text: string;
  category: CategoryKey;
}

export interface Career {
  title: string;
  description: string;
  primaryCodes: CategoryKey[];
  pathway: string;
}

export interface QuizResults {
  scores: Record<CategoryKey, number>;
  topThree: CategoryKey[];
  code: string;
}

import React, { useState, useMemo } from 'react';
import { QUESTIONS, CATEGORY_DESCRIPTIONS, CAREER_DATABASE, PATHWAYS_BY_CATEGORY } from './constants';
import { CategoryKey, QuizResults } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<'intro' | 'quiz' | 'results'>('intro');
  const [answers, setAnswers] = useState<Record<number, boolean>>({});
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);

  const handleAnswer = (val: boolean) => {
    setAnswers(prev => ({ ...prev, [QUESTIONS[currentQuestionIndex].id]: val }));
    if (currentQuestionIndex < QUESTIONS.length - 1) {
      setCurrentQuestionIndex(curr => curr + 1);
    } else {
      setStep('results');
    }
  };

  const results = useMemo((): QuizResults => {
    const scores: Record<CategoryKey, number> = { R: 0, I: 0, A: 0, S: 0, E: 0, C: 0 };
    QUESTIONS.forEach(q => {
      if (answers[q.id]) {
        scores[q.category]++;
      }
    });

    const topThree = (Object.keys(scores) as CategoryKey[])
      .sort((a, b) => scores[b] - scores[a])
      .slice(0, 3);

    return {
      scores,
      topThree,
      code: topThree.join('')
    };
  }, [answers]);

  if (step === 'intro') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-2xl w-full bg-white rounded-3xl shadow-xl p-8 md:p-12 text-center">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center mx-auto mb-6">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <h1 className="text-4xl font-bold text-slate-900 mb-4">Pathfinder Career Quest</h1>
          <p className="text-slate-600 text-lg mb-8 leading-relaxed">
            Discover your professional personality using the RIASEC model. Answer 42 simple questions about your interests to find your matching career pathways.
          </p>
          <button
            onClick={() => setStep('quiz')}
            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl transition-all shadow-lg hover:shadow-emerald-200"
          >
            Start Interest Test
          </button>
          <p className="mt-4 text-sm text-slate-400">Takes approximately 5-7 minutes</p>
        </div>
      </div>
    );
  }

  if (step === 'quiz') {
    const q = QUESTIONS[currentQuestionIndex];
    const progress = ((currentQuestionIndex + 1) / QUESTIONS.length) * 100;

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 flex flex-col items-center">
        <div className="max-w-xl w-full">
          <div className="mb-8">
            <div className="flex justify-between items-center mb-2">
              <span className="text-sm font-semibold text-emerald-600 uppercase tracking-wider">Question {currentQuestionIndex + 1} of 42</span>
              <span className="text-sm font-medium text-slate-400">{Math.round(progress)}% Complete</span>
            </div>
            <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden">
              <div className="bg-emerald-500 h-full transition-all duration-300" style={{ width: `${progress}%` }}></div>
            </div>
          </div>

          <div className="bg-white rounded-3xl shadow-lg p-8 md:p-12 mb-6 min-h-[300px] flex flex-col justify-center text-center">
            <h2 className="text-2xl md:text-3xl font-medium text-slate-800 leading-snug">
              "{q.text}"
            </h2>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button
              onClick={() => handleAnswer(true)}
              className="py-6 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-2xl shadow-lg transition-all active:scale-95 text-xl flex flex-col items-center"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
              YES
            </button>
            <button
              onClick={() => handleAnswer(false)}
              className="py-6 bg-white hover:bg-slate-50 text-slate-600 border-2 border-slate-200 font-bold rounded-2xl shadow-sm transition-all active:scale-95 text-xl flex flex-col items-center"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
              NO
            </button>
          </div>

          <button 
            onClick={() => setCurrentQuestionIndex(prev => Math.max(0, prev - 1))}
            className="mt-8 text-slate-400 hover:text-slate-600 text-sm font-medium underline underline-offset-4 w-full"
            disabled={currentQuestionIndex === 0}
          >
            Go Back to Previous Question
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <div className="bg-emerald-600 text-white pt-16 pb-24 px-4 text-center">
        <h2 className="text-emerald-100 text-sm font-bold uppercase tracking-widest mb-2">Quiz Results</h2>
        <h1 className="text-5xl font-black mb-4">My Interest Code: {results.code}</h1>
        <p className="max-w-2xl mx-auto opacity-90 text-lg">
          Based on your answers, these are the three areas that best describe your vocational interests.
        </p>
      </div>

      <div className="max-w-6xl mx-auto -mt-12 px-4 grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Top 3 Details */}
        <div className="lg:col-span-2 space-y-6">
          {results.topThree.map((key) => {
            const desc = CATEGORY_DESCRIPTIONS[key];
            const score = results.scores[key];
            return (
              <div key={key} className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                <div className="flex items-start justify-between mb-4">
                  <div>
                    <span className="inline-block px-3 py-1 bg-emerald-50 text-emerald-700 font-bold rounded-lg text-sm mb-2">Category: {key}</span>
                    <h3 className="text-2xl font-bold text-slate-900">{desc.title}</h3>
                  </div>
                  <div className="text-right">
                    <div className="text-3xl font-black text-emerald-600">{score}</div>
                    <div className="text-xs text-slate-400 font-bold uppercase">Points</div>
                  </div>
                </div>
                <p className="text-slate-600 leading-relaxed mb-6">
                  {desc.description}
                </p>

                <h4 className="font-bold text-slate-800 text-sm uppercase tracking-wider mb-4 border-b border-slate-100 pb-2">Matching Career Pathways</h4>
                <div className="flex flex-wrap gap-2">
                  {PATHWAYS_BY_CATEGORY[key].map(path => (
                    <span key={path} className="px-4 py-2 bg-slate-100 text-slate-700 rounded-full text-sm font-medium border border-slate-200">
                      {path}
                    </span>
                  ))}
                </div>
              </div>
            );
          })}
        </div>

        {/* Right Column: Score Summary & Occupations */}
        <div className="space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
            <h3 className="text-lg font-bold text-slate-900 mb-6 flex items-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2 text-emerald-500" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-12a1 1 0 10-2 0v4a1 1 0 00.293.707l2.828 2.829a1 1 0 101.415-1.415L11 9.586V6z" clipRule="evenodd" />
              </svg>
              Score Breakdown
            </h3>
            <div className="space-y-4">
              {(Object.keys(results.scores) as CategoryKey[]).map(key => (
                <div key={key}>
                  <div className="flex justify-between text-xs font-bold text-slate-400 mb-1">
                    <span>{CATEGORY_DESCRIPTIONS[key].title}</span>
                    <span>{results.scores[key]}/7</span>
                  </div>
                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${results.topThree.includes(key) ? 'bg-emerald-500' : 'bg-slate-300'}`} 
                      style={{ width: `${(results.scores[key] / 7) * 100}%` }}
                    ></div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-emerald-900 text-white rounded-2xl shadow-lg p-6 overflow-hidden relative">
            <div className="relative z-10">
              <h3 className="text-xl font-bold mb-4">Sample Occupations</h3>
              <p className="text-emerald-100 text-sm mb-6 leading-relaxed">
                Based on your primary interest ({CATEGORY_DESCRIPTIONS[results.topThree[0]].title}), here are some careers to explore:
              </p>
              <ul className="space-y-3">
                {CAREER_DATABASE[results.topThree[0]].slice(0, 10).map(occ => (
                  <li key={occ} className="flex items-center text-sm group">
                    <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full mr-3 group-hover:scale-150 transition-transform"></span>
                    {occ}
                  </li>
                ))}
              </ul>
              <button 
                onClick={() => window.location.reload()}
                className="mt-8 w-full py-3 bg-white text-emerald-900 font-bold rounded-xl text-sm hover:bg-emerald-50 transition-colors"
              >
                Retake Assessment
              </button>
            </div>
            {/* Background Decoration */}
            <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-emerald-800 rounded-full blur-3xl opacity-50"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

{
  "name": "Pathfinder: RIASEC Career Quest",
  "description": "A professional Holland Code career assessment tool for high school students to discover their vocational interests and explore hundreds of matching career paths.",
  "requestFramePermissions": []
}

import React, { useState, useMemo } from 'react';
import { QUESTIONS, CATEGORY_DESCRIPTIONS, CAREER_DATABASE, PATHWAYS_BY_CATEGORY } from './constants';
import { CategoryKey, QuizResults } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<'intro' | 'quiz' | 'results'>('intro');
  const [answers, setAnswers] = useState<Record<number, boolean>>({});
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [occupationSearch, setOccupationSearch] = useState('');

  const handleAnswer = (val: boolean) => {
    setAnswers(prev => ({ ...prev, [QUESTIONS[currentQuestionIndex].id]: val }));
    if (currentQuestionIndex < QUESTIONS.length - 1) {
      setCurrentQuestionIndex(curr => curr + 1);
    } else {
      setStep('results');
    }
  };

  const results = useMemo((): QuizResults => {
    const scores: Record<CategoryKey, number> = { R: 0, I: 0, A: 0, S: 0, E: 0, C: 0 };
    QUESTIONS.forEach(q => {
      if (answers[q.id]) {
        scores[q.category]++;
      }
    });

    const topThree = (Object.keys(scores) as CategoryKey[])
      .sort((a, b) => scores[b] - scores[a])
      .slice(0, 3);

    return {
      scores,
      topThree,
      code: topThree.join('')
    };
  }, [answers]);

  const filteredOccupations = useMemo(() => {
    const allMatching = results.topThree.flatMap(key => CAREER_DATABASE[key]);
    const unique = Array.from(new Set(allMatching));
    if (!occupationSearch) return unique;
    return unique.filter(occ => occ.toLowerCase().includes(occupationSearch.toLowerCase()));
  }, [results, occupationSearch]);

  if (step === 'intro') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-2xl w-full bg-white rounded-3xl shadow-xl p-8 md:p-12 text-center">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center mx-auto mb-6">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <h1 className="text-4xl font-bold text-slate-900 mb-4">Pathfinder: Career Quest</h1>
          <p className="text-slate-600 text-lg mb-8 leading-relaxed">
            Discover your unique professional DNA. This 42-question RIASEC test matches your interests to thousands of real-world career paths.
          </p>
          <button
            onClick={() => setStep('quiz')}
            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl transition-all shadow-lg hover:shadow-emerald-200"
          >
            Start My Quest
          </button>
          <div className="mt-6 flex items-center justify-center gap-4 text-xs font-bold text-slate-400 tracking-widest uppercase">
            <span>Realistic</span>
            <span>Investigative</span>
            <span>Artistic</span>
            <span>Social</span>
            <span>Enterprising</span>
            <span>Conventional</span>
          </div>
        </div>
      </div>
    );
  }

  if (step === 'quiz') {
    const q = QUESTIONS[currentQuestionIndex];
    const progress = ((currentQuestionIndex + 1) / QUESTIONS.length) * 100;

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 flex flex-col items-center">
        <div className="max-w-xl w-full">
          <div className="mb-12">
            <div className="flex justify-between items-center mb-3">
              <span className="text-xs font-black text-emerald-600 uppercase tracking-widest">Question {currentQuestionIndex + 1} of 42</span>
              <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{Math.round(progress)}% COMPLETE</span>
            </div>
            <div className="w-full bg-slate-200 h-3 rounded-full overflow-hidden shadow-inner">
              <div className="bg-emerald-500 h-full transition-all duration-300 ease-out shadow-sm" style={{ width: `${progress}%` }}></div>
            </div>
          </div>

          <div className="bg-white rounded-[2rem] shadow-2xl p-10 md:p-14 mb-8 min-h-[320px] flex flex-col justify-center text-center relative border border-slate-100">
            <div className="absolute top-6 left-1/2 -translate-x-1/2 w-12 h-1 bg-slate-100 rounded-full"></div>
            <h2 className="text-2xl md:text-3xl font-semibold text-slate-800 leading-tight">
              "{q.text}"
            </h2>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <button
              onClick={() => handleAnswer(true)}
              className="group py-8 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 text-xl flex flex-col items-center gap-2 border-b-4 border-emerald-800"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 transition-transform group-hover:scale-110" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
              YES
            </button>
            <button
              onClick={() => handleAnswer(false)}
              className="group py-8 bg-white hover:bg-slate-50 text-slate-400 hover:text-slate-600 border-2 border-slate-200 hover:border-slate-300 font-bold rounded-2xl shadow-md transition-all active:scale-95 text-xl flex flex-col items-center gap-2 border-b-4 border-slate-100"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 transition-transform group-hover:scale-110" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
              </svg>
              NO
            </button>
          </div>

          <div className="mt-12 flex justify-center">
            <button 
              onClick={() => setCurrentQuestionIndex(prev => Math.max(0, prev - 1))}
              className={`text-slate-400 hover:text-slate-600 text-sm font-bold uppercase tracking-widest flex items-center gap-2 transition-opacity ${currentQuestionIndex === 0 ? 'opacity-0 cursor-default' : 'opacity-100'}`}
              disabled={currentQuestionIndex === 0}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
              </svg>
              Previous
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      {/* Dynamic Header */}
      <div className="bg-slate-900 text-white pt-20 pb-28 px-4 text-center relative overflow-hidden">
        <div className="absolute inset-0 opacity-10 pointer-events-none">
          <svg className="w-full h-full" viewBox="0 0 100 100" preserveAspectRatio="none">
            <path d="M0 100 C 20 0 50 0 100 100 Z" fill="currentColor"></path>
          </svg>
        </div>
        <div className="relative z-10 max-w-4xl mx-auto">
          <span className="inline-block px-4 py-1.5 bg-emerald-500 text-white text-[10px] font-black uppercase tracking-[0.3em] rounded-full mb-6">Quest Complete</span>
          <h1 className="text-5xl md:text-7xl font-black mb-6 tracking-tight">
            Interest Code: <span className="text-emerald-400">{results.code}</span>
          </h1>
          <p className="text-slate-400 text-lg md:text-xl max-w-2xl mx-auto font-medium">
            Your results reveal a strong preference for <span className="text-white">{CATEGORY_DESCRIPTIONS[results.topThree[0]].title}</span> environments. Explore your personalized career matches below.
          </p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto -mt-16 px-4">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Main Content Area */}
          <div className="lg:col-span-8 space-y-8">

            {/* Top 3 Breakdown */}
            <section className="space-y-6">
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] px-2">Top Interest Areas</h2>
              {results.topThree.map((key, index) => {
                const desc = CATEGORY_DESCRIPTIONS[key];
                const score = results.scores[key];
                const maxInGroup = key === 'C' ? 8 : (key === 'A' ? 6 : 7); // Handle the skewed PDF data distribution
                return (
                  <div key={key} className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden flex flex-col md:flex-row">
                    <div className="p-8 flex-1">
                      <div className="flex items-center gap-3 mb-4">
                        <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-white text-xl" style={{ backgroundColor: desc.color }}>
                          {key}
                        </div>
                        <h3 className="text-2xl font-black text-slate-900">{desc.title}</h3>
                        <div className="ml-auto flex flex-col items-end">
                          <span className="text-3xl font-black text-slate-900 leading-none">{score}</span>
                          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Score</span>
                        </div>
                      </div>
                      <p className="text-slate-600 leading-relaxed mb-6 font-medium italic">"{desc.description}"</p>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Popular Majors</h4>
                          <div className="flex flex-wrap gap-2">
                            {desc.majors.map(major => (
                              <span key={major} className="px-3 py-1 bg-slate-50 text-slate-600 rounded-lg text-xs font-bold border border-slate-100">{major}</span>
                            ))}
                          </div>
                        </div>
                        <div>
                          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Related Pathways</h4>
                          <div className="flex flex-wrap gap-2">
                            {PATHWAYS_BY_CATEGORY[key].map(path => (
                              <span key={path} className="px-3 py-1 bg-emerald-50 text-emerald-700 rounded-lg text-xs font-bold border border-emerald-100">{path}</span>
                            ))}
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </section>

            {/* Comprehensive Occupation Database */}
            <section className="bg-white rounded-[2rem] shadow-xl border border-slate-100 p-10">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                <div>
                  <h2 className="text-2xl font-black text-slate-900 mb-2">Career Database</h2>
                  <p className="text-slate-500 text-sm font-medium">Matching occupations based on your top 3 interest areas.</p>
                </div>
                <div className="relative max-w-xs w-full">
                  <input 
                    type="text" 
                    placeholder="Search careers..." 
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium"
                    value={occupationSearch}
                    onChange={(e) => setOccupationSearch(e.target.value)}
                  />
                  <svg className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                {filteredOccupations.length > 0 ? (
                  filteredOccupations.map(occ => (
                    <div key={occ} className="group p-4 bg-slate-50 hover:bg-emerald-600 hover:text-white rounded-2xl transition-all duration-200 cursor-pointer border border-slate-100">
                      <div className="flex items-center justify-between">
                        <span className="font-bold text-sm tracking-tight">{occ}</span>
                        <svg className="w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7"></path></svg>
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="col-span-full py-20 text-center text-slate-400">
                    <p className="font-black uppercase tracking-widest text-xs">No matching occupations found</p>
                  </div>
                )}
