              <div className="mt-6 pt-6 border-t border-slate-100 text-center">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Source: Department of Labor O*NET Database</p>
              </div>
            </section>
          </div>

          {/* Sidebar Area */}
          <div className="lg:col-span-4 space-y-8">

