import React, { useState, useMemo } from 'react';
import { QUESTIONS, CATEGORY_DESCRIPTIONS, CAREER_DATABASE, PATHWAYS_BY_CATEGORY } from './constants';
import { CategoryKey, QuizResults } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<'intro' | 'quiz' | 'results'>('intro');
  const [answers, setAnswers] = useState<Record<number, boolean>>({});
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [occupationSearch, setOccupationSearch] = useState('');

  const handleAnswer = (val: boolean) => {
    setAnswers(prev => ({ ...prev, [QUESTIONS[currentQuestionIndex].id]: val }));
    if (currentQuestionIndex < QUESTIONS.length - 1) {
      setCurrentQuestionIndex(curr => curr + 1);
    } else {
      setStep('results');
    }
  };

  const results = useMemo((): QuizResults => {
    const scores: Record<CategoryKey, number> = { R: 0, I: 0, A: 0, S: 0, E: 0, C: 0 };
    QUESTIONS.forEach(q => {
      if (answers[q.id]) {
        scores[q.category]++;
      }
    });

    const topThree = (Object.keys(scores) as CategoryKey[])
      .sort((a, b) => scores[b] - scores[a])
      .slice(0, 3);

    return {
      scores,
      topThree,
      code: topThree.join('')
    };
  }, [answers]);

  const filteredOccupations = useMemo(() => {
    const allMatching = results.topThree.flatMap(key => CAREER_DATABASE[key]);
    // Fix: Explicitly cast unique to string array to resolve type inference issues
    const unique = Array.from(new Set(allMatching)) as string[];
    if (!occupationSearch) return unique;
    // Fix: Explicitly type occ as string to resolve 'unknown' type error
    return unique.filter((occ: string) => occ.toLowerCase().includes(occupationSearch.toLowerCase()));
  }, [results, occupationSearch]);

  if (step === 'intro') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-2xl w-full bg-white rounded-3xl shadow-xl p-8 md:p-12 text-center">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center mx-auto mb-6">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <h1 className="text-4xl font-bold text-slate-900 mb-4">Pathfinder: Career Quest</h1>
          <p className="text-slate-600 text-lg mb-8 leading-relaxed">
            Discover your unique professional DNA. This 42-question RIASEC test matches your interests to thousands of real-world career paths.
          </p>
          <button
            onClick={() => setStep('quiz')}
            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl transition-all shadow-lg hover:shadow-emerald-200"
          >
            Start My Quest
          </button>
          <div className="mt-6 flex items-center justify-center gap-4 text-xs font-bold text-slate-400 tracking-widest uppercase">
            <span>Realistic</span>
            <span>Investigative</span>
            <span>Artistic</span>
            <span>Social</span>
            <span>Enterprising</span>
            <span>Conventional</span>
          </div>
        </div>
      </div>
    );
  }

  if (step === 'quiz') {
    const q = QUESTIONS[currentQuestionIndex];
    const progress = ((currentQuestionIndex + 1) / QUESTIONS.length) * 100;

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 flex flex-col items-center">
        <div className="max-w-xl w-full">
          <div className="mb-12">
            <div className="flex justify-between items-center mb-3">
              <span className="text-xs font-black text-emerald-600 uppercase tracking-widest">Question {currentQuestionIndex + 1} of 42</span>
              <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{Math.round(progress)}% COMPLETE</span>
            </div>
            <div className="w-full bg-slate-200 h-3 rounded-full overflow-hidden shadow-inner">
              <div className="bg-emerald-500 h-full transition-all duration-300 ease-out shadow-sm" style={{ width: `${progress}%` }}></div>
            </div>
          </div>

          <div className="bg-white rounded-[2rem] shadow-2xl p-10 md:p-14 mb-8 min-h-[320px] flex flex-col justify-center text-center relative border border-slate-100">
            <div className="absolute top-6 left-1/2 -translate-x-1/2 w-12 h-1 bg-slate-100 rounded-full"></div>
            <h2 className="text-2xl md:text-3xl font-semibold text-slate-800 leading-tight">
              "{q.text}"
            </h2>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <button
              onClick={() => handleAnswer(true)}
              className="group py-8 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 text-xl flex flex-col items-center gap-2 border-b-4 border-emerald-800"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 transition-transform group-hover:scale-110" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
              YES
            </button>
            <button
              onClick={() => handleAnswer(false)}
              className="group py-8 bg-white hover:bg-slate-50 text-slate-400 hover:text-slate-600 border-2 border-slate-200 hover:border-slate-300 font-bold rounded-2xl shadow-md transition-all active:scale-95 text-xl flex flex-col items-center gap-2 border-b-4 border-slate-100"
